// Japanese Miner v6.2.8 cosmetic artwork bundle 6
(()=>{window.JM_RECOLOR_DATA=Object.assign(window.JM_RECOLOR_DATA||{},{"bun/hair/silver":"","bun/hair/teal":"","bun/jacket/academy":"","bun/jacket/explorer":"","bun/jacket/haori":"","bun/pants/black":"","bun/pants/denim":"","bun/pants/khaki":""});window.getJapaneseMinerRecolor=window.getJapaneseMinerRecolor||((hair,part,id)=>{const value=window.JM_RECOLOR_DATA[hair+'/'+part+'/'+id];return value?'url("data:image/webp;base64,'+value+'")':'none';});})();
